import{_ as e,c as l,a as t,o as r}from"./app-CEcM0piI.js";const o={};function s(n,i){return r(),l("div",null,i[0]||(i[0]=[t('<p><strong>⌚️投递时间：6.4</strong></p><p><strong>👋一面：6.12</strong></p><p><strong>🤏二面：6.17</strong></p><p><strong>一面（6.12）：</strong></p><ol><li>自我介绍</li><li>项目背景</li><li>项目亮点和难点</li><li>实现水平居中实现方案</li><li>数据类型</li><li>数组的常用函数</li><li>v-if和v-show</li><li>虚拟dom（主要是diff算法相关）</li><li>computed和method</li><li>父子组件通信</li><li>有使用过ai吗</li><li>你的优势</li><li>反问</li></ol><p>都是八股没有场景题......</p><p><strong>二面（6.13）： 23min</strong></p><ol><li>自我介绍</li><li>讲一下C++QT的项目（主包简历上有一个C++QT的项目）</li><li>项目中印象深刻的点</li><li>如果使用vue重构你会怎么设计</li><li>自选一个比较熟悉的工程化配置讲下。主包选的是webpack（简历上有写熟悉webpack和vite）</li><li>现场使用echarts实现简单的图表（主包的单线程大脑在紧张的时候不太能工作，遂换成看一下项目中的图表如何实现的，还好讲下来了）</li><li>问了里面封装的函数</li><li>问了下echarts中的tooltip配置</li><li>问了下图表数据的配置</li><li>工作地点是否可以接受</li><li>可以实习多久</li><li>反问</li></ol><p>好奇怪问了好多C++的那个项目，但主包简历上有两个vue项目和一个开源项目都不问!</p><p>面试官挺好的，还一直和鼠鼠说不要紧张，主包理解错的时候揽责说自己表述不清晰!</p><p>感觉大概率要寄了，面试时间好短，而且也没问很多</p><p>等结果ing......</p><p>作者：呆虫仙尊<br> 链接：<a href="https://www.nowcoder.com/discuss/762751110753832960?sourceSSR=users" target="_blank" rel="noopener noreferrer">https://www.nowcoder.com/discuss/762751110753832960?sourceSSR=users</a><br> 来源：牛客网</p>',13)]))}const p=e(o,[["render",s]]),c=JSON.parse('{"path":"/article/20250617/","title":"医渡云前端实习面试time line","lang":"zh-CN","frontmatter":{"title":"医渡云前端实习面试time line","createTime":"2025/06/17 19:30","tags":["面经","前端"],"permalink":"/article/20250617/"},"readingTime":{"minutes":1.48,"words":444},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"面试/医渡云前端实习面试time line.md","headers":[],"categoryList":[{"id":"1573c7","sort":10000,"name":"面试"}]}');export{p as comp,c as data};
